const aSl=$('#fr-a'), bSl=$('#fr-b'), pSel=$('#fr-p');
const aV=$('#fr-aVal'), bV=$('#fr-bVal');
const svg=$('#fr-svg'), out=$('#fr-out');
function draw(){
  const a=+aSl.value, b=+bSl.value, p=+pSel.value;
  aV.textContent=a; bV.textContent=b;
  const A = Math.pow(a,p), B = Math.pow(b,p);
  const C = Math.pow(A+B, 1/p);       // numerical c (not integer)
  const logDelta = 2*p*Math.log10(a*b*C) - 8*Math.log10(2);
  // roots: x = -B, 0, A.   domain [-B-1, A+1]
  svg.innerHTML='';
  const W=640, H=260, pad=30;
  const xmin=-B-1, xmax=A+1;
  // If too extreme, compress via signed log
  const sx = v => {
    const s = Math.sign(v), lv = s*Math.log10(1+Math.abs(v));
    return lv;
  };
  const u0=sx(xmin), u1=sx(xmax);
  const X = v => pad + (sx(v)-u0)/(u1-u0) * (W-2*pad);
  // y axis: f(x)=x(x-A)(x+B); sample to find range of y=±sqrt(f)
  const N=400;
  let ymax=1;
  const xs=[], fs=[];
  for(let i=0;i<=N;i++){
    const t=i/N; const x = xmin + t*(xmax-xmin);
    const f = x*(x-A)*(x+B);
    xs.push(x); fs.push(f);
    if(f>0) ymax = Math.max(ymax, Math.sqrt(f));
  }
  ymax = Math.max(ymax, 1);
  const Y = y => H/2 - (y/ymax)*(H/2 - pad);
  // axes
  svg.appendChild(SVG('line',{x1:pad,y1:H/2,x2:W-pad,y2:H/2,stroke:'var(--line)'}));
  // roots as yellow dots + labels
  [[-B,'−bᵖ'],[0,'0'],[A,'aᵖ']].forEach(([v,lab])=>{
    svg.appendChild(SVG('circle',{cx:X(v),cy:H/2,r:4,fill:'var(--yellow)'}));
    const t=SVG('text',{x:X(v),y:H/2+18,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    t.textContent = lab;
    svg.appendChild(t);
  });
  // curve: upper branch where f>=0, then lower branch
  let dU='', dL='';
  let upOpen=false, lowOpen=false;
  for(let i=0;i<xs.length;i++){
    const x=xs[i], f=fs[i];
    if(f>=0){
      const yy=Math.sqrt(f);
      const px=X(x), pyU=Y(yy), pyL=Y(-yy);
      dU += (upOpen?' L':'M')+px+' '+pyU;
      dL += (lowOpen?' L':'M')+px+' '+pyL;
      upOpen=true; lowOpen=true;
    } else { upOpen=false; lowOpen=false; }
  }
  svg.appendChild(SVG('path',{d:dU,fill:'none',stroke:'var(--cyan)','stroke-width':1.8}));
  svg.appendChild(SVG('path',{d:dL,fill:'none',stroke:'var(--cyan)','stroke-width':1.8}));
  // legend
  const lg=SVG('text',{x:W-pad,y:20,'text-anchor':'end','font-size':12,fill:'var(--mute)'});
  lg.textContent = 'E : y² = x(x − aᵖ)(x + bᵖ)';
  svg.appendChild(lg);

  out.textContent =
    `a=${a},  b=${b},  p=${p}\n`+
    `aᵖ = ${A}    bᵖ = ${B}    cᵖ = aᵖ+bᵖ = ${A+B}    c ≈ ${C.toFixed(4)}\n`+
    `2-torsion: (0,0),  (aᵖ,0) = (${A},0),  (−bᵖ,0) = (${-B},0)\n`+
    `Δ = (abc)^{2p}/2^{8}   →   log₁₀ Δ ≈ ${logDelta.toFixed(2)}\n`+
    `(semistable away from 2; conductor N_E squarefree outside 2)`;
}
aSl.oninput=draw; bSl.oninput=draw; pSel.onchange=draw;
draw();

