const aI=$('#cd-a'), bI=$('#cd-b'), pSel=$('#cd-p'), pre=$('#cd-preset');
const svg=$('#cd-svg'), out=$('#cd-out');
// small-prime sieve
const PRIMES = (()=>{ const lim=2000, ok=new Array(lim+1).fill(true); ok[0]=ok[1]=false;
  for(let i=2;i*i<=lim;i++) if(ok[i]) for(let j=i*i;j<=lim;j+=i) ok[j]=false;
  return ok.map((v,i)=>v?i:-1).filter(i=>i>0);
})();
function factor(n){
  n = Math.abs(n|0);
  const f = {};
  if(n<=1) return f;
  for(const q of PRIMES){
    if(q*q>n) break;
    while(n%q===0){ f[q]=(f[q]||0)+1; n=n/q; }
  }
  if(n>1) f[n]=(f[n]||0)+1;
  return f;
}
function gcd(a,b){ a=Math.abs(a|0); b=Math.abs(b|0); while(b){ [a,b]=[b,a%b]; } return a; }
function fmtFact(f){
  const ks = Object.keys(f).map(k=>+k).sort((x,y)=>x-y);
  if(!ks.length) return '1';
  return ks.map(k => f[k]===1 ? String(k) : `${k}^${f[k]}`).join(' · ');
}
pre.addEventListener('change', ()=>{
  const v = pre.value; if(!v) return;
  const [x,y] = v.split(',').map(s=>+s);
  aI.value = x; bI.value = y; draw();
});
function draw(){
  const a=Math.max(1,Math.min(999,+aI.value||1));
  const b=Math.max(1,Math.min(999,+bI.value||1));
  const p=+pSel.value;
  const g = gcd(a,b);
  const c = a+b;                              // integer stand-in for c = (a^p+b^p)^{1/p}; we only need primes dividing abc
  const fa = factor(a), fb = factor(b), fc = factor(c);
  // odd primes dividing abc:
  const oddSupport = new Set();
  for(const f of [fa,fb,fc]) for(const q of Object.keys(f)){ const Q=+q; if(Q!==2) oddSupport.add(Q); }
  const oddList = [...oddSupport].sort((x,y)=>x-y);
  // conductor (semistable model): N_E = 2 * prod(odd bad primes)
  const N = 2 * oddList.reduce((s,q)=>s*q, 1);

  // draw a linear "factor tower": primes as boxes along a number line, with exponent 2p shown
  svg.innerHTML='';
  const W=640, H=200, pad=40;
  // headline: Δ = (abc)^{2p}/2^8, conductor below
  const hd = SVG('text',{x:W/2, y:24, 'text-anchor':'middle','font-size':13, fill:'var(--mute)'});
  hd.textContent = `Δ = (abc)^{2p}/2^{8}    with abc = ${a}·${b}·${c} = ${a*b*c}`;
  svg.appendChild(hd);

  // top row: the primes from factor(abc) with combined exponents (scaled by 2p for odd, and the raw exponent − 8/p-ish shown schematically for 2)
  const abcF = {};
  for(const f of [fa,fb,fc]) for(const [q,e] of Object.entries(f)){ abcF[q]=(abcF[q]||0)+e; }
  const qs = Object.keys(abcF).map(k=>+k).sort((x,y)=>x-y);
  const box = 72, gap = 14;
  const total = qs.length*box + Math.max(qs.length-1,0)*gap;
  let x0 = (W-total)/2;
  qs.forEach((q,i)=>{
    const ex = abcF[q];
    const isTwo = (q===2);
    const cx = x0 + i*(box+gap) + box/2;
    const color = isTwo ? 'var(--pink)' : 'var(--cyan)';
    svg.appendChild(SVG('rect',{x:cx-box/2, y:50, width:box, height:52, rx:6,
      fill:'var(--panel2)', stroke:color, 'stroke-width':1.5}));
    const t1 = SVG('text',{x:cx, y:72, 'text-anchor':'middle','font-size':14, fill:color,'font-weight':600});
    t1.textContent = 'ℓ = '+q;
    svg.appendChild(t1);
    const t2 = SVG('text',{x:cx, y:92, 'text-anchor':'middle','font-size':11, fill:'var(--mute)'});
    t2.textContent = isTwo ? `v_2(abc)=${ex}` : `v_ℓ(Δ)=${2*p*ex}`;
    svg.appendChild(t2);
    // exponent decoration: odd primes carry an exponent that is a multiple of 2p → double circle
    if(!isTwo){
      svg.appendChild(SVG('circle',{cx, cy:50-6, r:6, fill:'var(--cyan)','opacity':0.35}));
      svg.appendChild(SVG('circle',{cx, cy:50-6, r:3, fill:'var(--cyan)'}));
    }
  });

  // bottom: conductor formula
  const cond = SVG('text',{x:W/2, y:135, 'text-anchor':'middle','font-size':14, fill:'var(--yellow)','font-weight':600});
  cond.textContent = `N_E  =  2 · ${oddList.length?oddList.join(' · '):'1'}  =  ${N}`;
  svg.appendChild(cond);

  const ribetTarget = SVG('text',{x:W/2, y:160, 'text-anchor':'middle','font-size':12, fill:'var(--green)'});
  ribetTarget.textContent = oddList.length
    ? `Ribet strips ${oddList.length} odd prime${oddList.length>1?'s':''} → target level = 2`
    : `Already at level 2 — nothing to strip.`;
  svg.appendChild(ribetTarget);

  const flt = SVG('text',{x:W/2, y:184, 'text-anchor':'middle','font-size':12, fill:'var(--pink)','font-style':'italic'});
  flt.textContent = 'dim S_2(Γ_0(2)) = 0 → no such newform exists → no (a,b,c,p) triple exists';
  svg.appendChild(flt);

  // readout
  const notCo = (g!==1);
  const parts = [];
  parts.push(`a = ${a}   =  ${fmtFact(fa)||'1'}`);
  parts.push(`b = ${b}   =  ${fmtFact(fb)||'1'}`);
  parts.push(`c = a+b = ${c}   =  ${fmtFact(fc)||'1'}     (primes dividing c shown as proxy for c^p)`);
  parts.push(`gcd(a,b) = ${g}${notCo?'  ⚠ a,b not coprime — FLT reduces to the coprime case, so the widget warns but still computes':''}`);
  parts.push(`odd primes dividing abc : ${oddList.length?oddList.join(', '):'(none)'}`);
  parts.push(`bad reduction primes of E_{a,b,c}: { 2, ${oddList.join(', ')} }`);
  parts.push(`Δ prime factorization (symbolic):  2^{v_2(abc)·2p − 8} · ${oddList.map(q=>`${q}^{${2*p*(abcF[q]||0)}}`).join(' · ')||'1'}`);
  parts.push(`conductor N_E = 2 · ∏(odd ℓ | abc) ℓ = ${N}`);
  parts.push(`Ribet goal: level ${N} → … → 2.  Target space S_2(Γ_0(2)) is empty, so the chain cannot terminate.`);
  parts.push(`VERDICT: the hypothetical Frey curve for (a,b,p) = (${a},${b},${p}) would be modular (Wiles §2) yet force level-lowering to the empty space S_2(Γ_0(2)) — contradiction.`);
  out.textContent = parts.join('\n');
}
aI.addEventListener('input',draw); bI.addEventListener('input',draw); pSel.addEventListener('change',draw);
draw();

