let chain = []; // array of {level, odds, removed}  where odds=[odd primes still present], removed=the prime just stripped
let autoTimer = null;
function factorOdd(N){
  const out = []; let n = Math.abs(N|0); if(n%2===0) n=n/2; // strip the 2
  for(let q=3; q*q<=n; q+=2){ while(n%q===0){ out.push(q); n=n/q; } }
  if(n>1) out.push(n);
  // dedupe (semistable → squarefree)
  return [...new Set(out)].sort((a,b)=>a-b);
}
function start(){
  const N = +pick.value;
  const odds = factorOdd(N);
  chain = [{ level:N, odds, removed:null }];
}
function stepOnce(){
  const last = chain[chain.length-1];
  if(!last.odds.length) return; // already at level 2 (or no more odd primes)
  // strip the largest odd prime (cosmetic — Ribet works one prime at a time; order matters for bookkeeping but not the result)
  const odds = last.odds.slice();
  const removed = odds.pop();
  const level = last.level / removed;
  chain.push({ level, odds, removed });
}
