function start(){
  const N = +pick.value;
  const odds = factorOdd(N);
  chain = [{ level:N, odds, removed:null }];
}
function stepOnce(){
  const last = chain[chain.length-1];
  if(!last.odds.length) return; // already at level 2 (or no more odd primes)
  // strip the largest odd prime (cosmetic — Ribet works one prime at a time; order matters for bookkeeping but not the result)
  const odds = last.odds.slice();
  const removed = odds.pop();
  const level = last.level / removed;
  chain.push({ level, odds, removed });
}
function draw(){
  svg.innerHTML='';
  const W=700, H=260;
  const n = chain.length;
  // layout: horizontal chain of boxes
  const boxW=120, boxH=66;
  const totalW = n*boxW + (n-1)*60;
  const x0 = (W-totalW)/2;
  const y = 90;
  // arrows (behind boxes)
  for(let i=0;i<n-1;i++){
    const ax = x0 + i*(boxW+60) + boxW;
    const bx = x0 + (i+1)*(boxW+60);
    const midx = (ax+bx)/2;
    drawArrow(svg, [ax, y+boxH/2], [bx, y+boxH/2],
      {color:'var(--violet)', markerId:'st-arr', pad1:4, pad2:8, width:1.5, label:'drop ℓ='+chain[i+1].removed, labelSide:1});
  }
  // boxes
  for(let i=0;i<n;i++){
    const node = chain[i];
    const bx = x0 + i*(boxW+60);
    const atTwo = (node.level===2);
    const stroke = atTwo ? 'var(--pink)' : (i===n-1 ? 'var(--yellow)' : 'var(--blue)');
    svg.appendChild(SVG('rect',{x:bx, y, width:boxW, height:boxH, rx:8,
      fill:'var(--panel2)', stroke, 'stroke-width':1.8}));
    const t1 = SVG('text',{x:bx+boxW/2, y:y+22, 'text-anchor':'middle','font-size':13,fill:'#fff','font-weight':600});
    t1.textContent = 'level '+node.level;
    svg.appendChild(t1);
    const t2 = SVG('text',{x:bx+boxW/2, y:y+40, 'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    t2.textContent = node.odds.length ? 'odd: '+node.odds.join(',') : 'odd: (none)';
    svg.appendChild(t2);
    const t3 = SVG('text',{x:bx+boxW/2, y:y+56, 'text-anchor':'middle','font-size':11,fill:'var(--cyan)'});
    t3.textContent = 'ρ̄ modular';
    svg.appendChild(t3);
  }
  // legend line
  const lg = SVG('text',{x:W/2, y:30, 'text-anchor':'middle','font-size':13, fill:'var(--mute)'});
  lg.textContent = 'ρ̄ = mod-p Galois representation of the Frey curve — fixed across the chain; only the newform level changes';
  svg.appendChild(lg);

  // termination flag
  const last = chain[chain.length-1];
  if(last.level===2){
    const flag = SVG('text',{x:W/2, y:y+boxH+36, 'text-anchor':'middle','font-size':13,fill:'var(--pink)','font-weight':600});
    flag.textContent = 'Landed at level 2 — but dim S_2(Γ_0(2)) = 0. No newform here. ✗';
    svg.appendChild(flag);
    const flt = SVG('text',{x:W/2, y:y+boxH+56, 'text-anchor':'middle','font-size':12,fill:'var(--green)','font-style':'italic'});
    flt.textContent = 'Contradiction ⇒ Fermat\u2019s last theorem.';
    svg.appendChild(flt);
  } else if(!last.odds.length){
    const flag = SVG('text',{x:W/2, y:y+boxH+36, 'text-anchor':'middle','font-size':13,fill:'var(--yellow)'});
    flag.textContent = 'No more odd primes to strip; level stabilizes at '+last.level+'.';
    svg.appendChild(flag);
  }

  // readout
  const lines = chain.map((c,i)=>{
    const arrow = (i===0) ? 'start' : `via ℓ=${c.removed}`;
    return `[step ${i}]  level=${c.level}  odd support=${c.odds.length?c.odds.join('·'):'(none)'}   (${arrow})`;
  });
  lines.push('');
  if(last.level===2) lines.push('→ Ribet chain terminates in the empty space S_2(Γ_0(2)). FLT closed.');
  else if(!last.odds.length) lines.push('→ Chain stops: no odd prime remains to strip.');
  else lines.push('→ Click "next step" to remove ℓ = '+last.odds[last.odds.length-1]+' from the level.');
  out.textContent = lines.join('\n');
}
function stopAuto(){ if(autoTimer){ clearInterval(autoTimer); autoTimer=null; auto.classList.remove('active'); auto.textContent='auto-run'; } }
pick.addEventListener('change', ()=>{ stopAuto(); start(); draw(); });
next.addEventListener('click', ()=>{ stopAuto(); stepOnce(); draw(); });
reset.addEventListener('click', ()=>{ stopAuto(); start(); draw(); });
auto.addEventListener('click', ()=>{
  if(autoTimer){ stopAuto(); return; }
  auto.classList.add('active'); auto.textContent='pause';
  autoTimer = setInterval(()=>{
    const last = chain[chain.length-1];
    if(!last.odds.length){ stopAuto(); return; }
    stepOnce(); draw();
  }, 750);
});
start(); draw();

const state = { ram3:false, ram5:false, ord:true };
const btns = $$('.df-tog'), out = $('#df-out');
function render(){
  // toy model: dim = base 0 + 1 per extra ramification prime + 1 if non-ordinary (irregular local condition)
  let dim = 0;
  let narr = [];
  narr.push('Residual $\\overline\\rho$ ramified at $\\{2, p\\}$; start with trivial Selmer.');
  if(state.ram3){ dim++; narr.push('allow ramification at 3 → +1 local tangent direction'); }
  if(state.ram5){ dim++; narr.push('allow ramification at 5 → +1 local tangent direction'); }
  if(!state.ord){ dim++; narr.push('drop ordinary condition at p → +1 Selmer dimension'); }
  btns.forEach(b=>{ const k=b.dataset.k; b.textContent = state[k] ? 'on' : 'off'; b.classList.toggle('active', state[k]); });
  out.textContent =
    narr.map(s=>'• '+s.replace(/\\\$/g,'').replace(/\\\\/g,'')).join('\n') + '\n' +
    `Relative Selmer dim (toy count): ${dim}\n`+
    `R_Σ is a quotient of Z_p[[x_1,…,x_${Math.max(dim,1)}]] (dim ≤ ${dim}).`;
}
btns.forEach(b=>b.addEventListener('click',()=>{ state[b.dataset.k] = !state[b.dataset.k]; render(); }));
render();

