const sl=$('#rt-n'), sv=$('#rt-nv'), svg=$('#rt-svg'), out=$('#rt-out');
function draw(){
  const n=+sl.value; sv.textContent='n='+n;
  svg.innerHTML='';
  const W=640,H=200,pad=30;
  // two stacks of boxes: R on left, T on right; each grows with n
  const boxH = 22, gap = 4;
  function stack(x, label, count, color){
    const t = SVG('text',{x, y:30, 'text-anchor':'middle','font-size':14,fill:color,'font-weight':600});
    t.textContent = label; svg.appendChild(t);
    for(let i=0;i<count;i++){
      svg.appendChild(SVG('rect',{x:x-60, y:50+i*(boxH+gap), width:120, height:boxH,
        fill:'var(--panel2)', stroke:color, 'stroke-width':1.5, rx:4}));
      const tt = SVG('text',{x, y:50+i*(boxH+gap)+boxH*0.7, 'text-anchor':'middle','font-size':11,fill:'var(--ink)'});
      tt.textContent = (label==='R_n' ? 'x_'+(i+1) : 'T_{ℓ_'+(i+1)+'}');
      svg.appendChild(tt);
    }
  }
  stack(180, 'R_n', n+1, 'var(--violet)');
  stack(460, 'T_n', n+1, 'var(--cyan)');
  // equal sign when n≥6 (limit reached in this toy)
  const eq = SVG('text',{x:320, y:120, 'text-anchor':'middle','font-size':28,
    fill: n>=6 ? 'var(--green)' : 'var(--mute)', 'font-weight':700});
  eq.textContent = (n>=6 ? 'R = T' : 'R ↠ T');
  svg.appendChild(eq);

  out.textContent =
    `Patching level n = ${n}\n`+
    `Auxiliary Taylor–Wiles primes Q_n: |Q_n| = ${n}.\n`+
    `R_n := R_{Σ∪Q_n},   T_n := T_{Σ∪Q_n}.\n`+
    `At each finite n, R_n ≅ Z_p[[x_1,…,x_${n+1}]]/I_n and T_n has the same form.\n`+
    (n<6 ? 'Surjection R_n ↠ T_n; equality not yet forced.' :
           'Limit: R_Σ ≅ T_Σ. Every Σ-ramified deformation of ρ̄ is modular.');
}
sl.oninput = draw; draw();

